        if err != nil {
            return nil, err
        }

        // Convert result to boolean using JavaScript truthiness
        boolResult, err := value.ToBoolean()
        if err != nil {
            return nil, err
        }

        if boolResult {
            // Create a copy of the map to avoid potential issues with reference semantics
            // if the caller modifies the returned slice or the original items later.
            itemCopy := make(map[string]interface{})
            for k, v := range item {
