package main

import (
	"fmt"
	"github.com/robertkrimen/otto"
)

// FilterItems executes a JavaScript condition script for each item in the slice.
// It returns a new slice containing only the items for which the script evaluates to true.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	// Create a new Otto VM instance for the filtering operation.
	vm := otto.New()

	// Prepare the result slice.
	var filteredItems []map[string]interface{}

	// Iterate over each item in the input slice.
	for _, item := range items {
		// Inject the current item into the JavaScript environment as a global variable named 'item'.
		// We pass the map directly; otto handles the conversion to a JavaScript object.
		err := vm.Set("item", item)
		if err != nil {
			return nil, fmt.Errorf("failed to set 'item' variable in VM: %w", err)
		}

		// Execute the condition script.
		value, err := vm.Run(conditionScript)
		if err != nil {
			return nil, fmt.Errorf("failed to execute condition script: %w", err)
		}

		// Check if the script result is truthy.
		// otto's truthiness rules are standard: undefined, null, 0, "", NaN are falsy.
		// We use the truthy check directly from otto.Value.
		if value.IsBoolean() {
			// If it's a boolean, check its actual boolean value
			if boolVal, err := value.ToBoolean(); err == nil && boolVal {
				filteredItems = append(filteredItems, item)
			}
		} else {
			// For non-boolean values, check truthiness
			if truthy, err := value.ToBoolean(); err == nil && truthy {
				filteredItems = append(filteredItems, item)
			}
		}
	}

	return filteredItems, nil
}

func main() {
	// Example usage of FilterItems.
	// This demonstrates how the function works with sample data.

	// Sample data: A slice of maps representing items.
	items := []map[string]interface{}{
		{"name": "Apple", "price": 1.20, "category": "fruit"},
		{"name": "Carrot", "price": 0.80, "category": "vegetable"},
		{"name": "Banana", "price": 0.50, "category": "fruit"},
		{"name": "Potato", "price": 0.30, "category": "vegetable"},
	}

	// Sample condition script: Select items that are fruits and cost more than 0.60.
	// We can access properties of the 'item' object directly.
	conditionScript := `item.category == 'fruit' && item.price > 0.60`

	// Execute the filter.
	filtered, err := FilterItems(conditionScript, items)
	if err != nil {
		fmt.Printf("Error filtering items: %v\n", err)
		return
	}

	// Print the results.
	fmt.Println("Original items:")
	for _, item := range items {
		fmt.Printf("  %v\n", item)
	}

	fmt.Println("\nFiltered items (Fruit with price > 0.60):")
	if len(filtered) == 0 {
		fmt.Println("  No items matched.")
	} else {
		for _, item := range filtered {
			fmt.Printf("  %v\n", item)
		}
	}
}

